SELECT *
FROM t_oa_cost_apply


        AND (INSTR(apply_no,#{queryForm.keywords})
        OR INSTR(create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(apply_date, '%Y-%m-%d') >= #{queryForm.applyDateBegin}


        AND DATE_FORMAT(apply_date, '%Y-%m-%d') <= #{queryForm.applyDateEnd}


        AND department_id = #{queryForm.departmentId}


        AND enterprise_id = #{queryForm.enterpriseId}



    ORDER BY create_time DESC

